const item = $input.first().json;

function decodeMimeWord(str) {
  if (!str || typeof str !== "string") return "";

  return str.replace(/=\?([^?]+)\?([BQbq])\?([^?]+)\?=/g, (_, charset, encoding, text) => {
    try {
      if (encoding.toUpperCase() === "B") {
        return Buffer.from(text, "base64").toString("utf8");
      }

      // Q-encoding
      const qp = text
        .replace(/_/g, " ")
        .replace(/=([A-Fa-f0-9]{2})/g, (_, hex) =>
          String.fromCharCode(parseInt(hex, 16))
        );

      return Buffer.from(qp, "binary").toString("utf8");
    } catch {
      return text;
    }
  });
}

function cleanHeader(value) {
  if (value === null || value === undefined) return "";

  if (Array.isArray(value)) {
    value = value.join(" ");
  }

  if (typeof value !== "string") {
    value = String(value);
  }

  return decodeMimeWord(value).replace(/^[A-Za-z-]+:\s*/, "").trim();
}

function parseAddressField(value) {
  if (!value) {
    return {
      text: "",
      name: "",
      email: "",
    };
  }

  // Already plain string
  if (typeof value === "string") {
    const cleaned = cleanHeader(value);
    const match = cleaned.match(/^(.*?)(?:\s*<([^>]+)>)?$/);

    return {
      text: cleaned,
      name: match?.[1]?.trim().replace(/^"|"$/g, "") || "",
      email: match?.[2]?.trim() || "",
    };
  }

  // Common object format from n8n/mailparser-style fields
  if (typeof value === "object") {
    if (value.text) {
      const cleaned = cleanHeader(value.text);
      const first = value.value?.[0];

      return {
        text: cleaned,
        name: first?.name ? decodeMimeWord(first.name).trim() : "",
        email: first?.address || "",
      };
    }

    // Sometimes just { address, name }
    if (value.address || value.name) {
      const name = value.name ? decodeMimeWord(String(value.name)).trim() : "";
      const email = value.address ? String(value.address).trim() : "";
      return {
        text: name && email ? `${name} <${email}>` : name || email,
        name,
        email,
      };
    }

    // Sometimes array-like inside object
    if (Array.isArray(value.value) && value.value.length > 0) {
      const first = value.value[0];
      const name = first?.name ? decodeMimeWord(String(first.name)).trim() : "";
      const email = first?.address ? String(first.address).trim() : "";
      return {
        text: name && email ? `${name} <${email}>` : name || email,
        name,
        email,
      };
    }
  }

  return {
    text: cleanHeader(value),
    name: "",
    email: "",
  };
}

function cleanBody(text) {
  if (!text) return "";

  return String(text)
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n")
    .replace(/\\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .replace(/[ \t]{2,}/g, " ")
    .trim();
}

const fromParsed = parseAddressField(item.from);
const toParsed = parseAddressField(item.to);

return [
  {
    json: {
      id: item.id ?? "",
      threadId: item.threadId ?? "",

      subject: cleanHeader(item.subject),
      date: cleanHeader(item.date),

      from: fromParsed.text,
      fromName: fromParsed.name,
      fromEmail: fromParsed.email,

      to: toParsed.text,
      toName: toParsed.name,
      toEmail: toParsed.email,

      body: cleanBody(item.text || item.html || ""),
      html: item.html || "",
    },
  },
];

const item = $input.first().json;

let body = item.body || "";

// convert ANY escaped newline into real newline
body = body.replace(/\s*\\n\s*/g, "\n");
body = body.replace(/\s*\\r\s*/g, "\n");
body = body.replace(/\s*\\r\\n\s*/g, "\n");

// remove URLs
body = body.replace(/https?:\/\/[^\s]+/g, "");

// remove tracking params
body = body.replace(/trackingId=[^\s]+/gi, "");

// remove long junk tokens
body = body.replace(/[A-Za-z0-9_-]{30,}/g, "");

// remove LinkedIn footer
body = body.replace(/Manage your job alerts[\s\S]*/i, "");

// normalize whitespace
body = body.replace(/[ \t]+/g, " ");
body = body.replace(/\n{3,}/g, "\n\n");

body = body
  .split("\n")
  .map(line => line.trim())
  .filter(line => line.length > 2)
  .join("\n")
  .trim();

return [
  {
    json: {
      ...item,
      cleanBody: body,
    },
  },
];
